// ponytail: hand-rolled runtime service worker. vite-plugin-pwa's Workbox SW
// generation doesn't fire under Vite 8 + @cloudflare/vite-plugin's named ssr
// environment, so we ship a tiny SW directly. It does three things:
//
//   1. PRECACHE the app shell at install — so a cold open offline boots the
//      app. The shell (/_shell.html) is generated by tanstackStart({spa}) at
//      build time as an empty app document (no route data); the router takes
//      over client-side once it loads.
//   2. NAVIGATION FALLBACK — any document navigation that can't be served
//      from cache falls back to the cached shell, so the app always boots
//      instead of showing the browser's offline error page.
//   3. RUNTIME SWR for same-origin GETs (assets + the GET server-fn RPC
//      responses) — so last-known data (directory list, session, etc.) is
//      served offline. Mutations are POST and never enter here.
//
// The shell's build-hashed CSS/JS are precached at install by parsing the
// shell HTML for its own /assets/*.{css,js} URLs (see install below). Without
// this, cache-first navigation served the shell instantly while CSS round-
// tripped the network → a flash of unstyled (text-only) content on slow
// connections. The shell is the source of truth for its own hashes, so no
// build-time precache manifest is needed. Route chunks lazy-loaded after
// hydration are still covered by runtime SWR.
//
// CACHE mirrors the app version in package.json. Bump BOTH together (here +
// package.json `version`) when you must force-invalidate every installed PWA
// client at once — e.g. a release with breaking server/API/DB changes or a
// shell-shape change. For backward-compatible releases, SWR + skipWaiting
// refreshes content within one reload.
const CACHE = 'psico-support-1.3.0'

// ponytail: the static SPA shell generated at build time. Served on cold-open
// offline and as the navigation fallback. Use the canonical /_shell URL (the
// .html form 307-redirects to this); avoids the SW caching a redirect.
const SHELL = '/_shell'
const PRECACHE = [
  SHELL,
  '/manifest.webmanifest',
  '/logo192.png',
  '/logo512.png',
  '/favicon.ico',
]

self.addEventListener('install', (event) => {
  event.waitUntil(
    (async () => {
      const cache = await caches.open(CACHE)
      // best-effort: addAll rejects if any single fetch fails; cache each so
      // one missing icon doesn't block the shell.
      await Promise.allSettled(PRECACHE.map((url) => cache.add(url)))
      // Precache the shell's own build-hashed CSS/JS. The shell HTML already
      // references its exact asset hashes, so parse them out and cache.addAll
      // them — no build-time manifest injection needed. This is what prevents
      // the FOUC: without it, cache-first navigation paints the shell while
      // CSS/JS round-trip the network (visible as unstyled text on slow links).
      // cache.match returns a fresh clone, so consuming .text() here does NOT
      // evict the cached shell entry.
      try {
        const shellRes = await cache.match(SHELL)
        if (shellRes) {
          const html = await shellRes.text()
          await Promise.allSettled(
            shellAssetUrls(html).map((url) => cache.add(url)),
          )
        }
      } catch {
        /* best-effort; runtime SWR still covers assets on later visits */
      }
      self.skipWaiting()
    })(),
  )
})

// ponytail: extract the shell's hashed stylesheet + script URLs for precaching.
// Matches root-relative /assets/*.{css,js} in href/src — covers the stylesheet
// <link>, <script src>, and modulepreload <link href>. Ignores cross-origin
// and non-/assets/ URLs (favicon etc. are already in PRECACHE).
function shellAssetUrls(html) {
  const urls = new Set()
  const re = /(?:href|src)="(\/assets\/[^"]+\.(?:css|js))"/g
  let m
  while ((m = re.exec(html))) urls.add(m[1])
  return [...urls]
}

self.addEventListener('activate', (event) => {
  event.waitUntil(
    (async () => {
      const keys = await caches.keys()
      await Promise.all(
        keys.filter((k) => k !== CACHE).map((k) => caches.delete(k)),
      )
      await self.clients.claim()
    })(),
  )
})

self.addEventListener('fetch', (event) => {
  const req = event.request
  if (req.method !== 'GET') return
  const sameOrigin = new URL(req.url).origin === self.location.origin
  if (!sameOrigin) return

  // ponytail: document navigations fall back to the cached shell when the
  // network (and any per-URL cache entry) is unavailable. This is what makes
  // the app boot offline from a cold start. Online navigations to SSR routes
  // (the profile page) still go to the worker first and get cached by the
  // SWR branch below on success.
  if (req.mode === 'navigate') {
    event.respondWith(
      (async () => {
        const cache = await caches.open(CACHE)
        // Prefer a cached response for THIS exact URL (e.g. a visited SSR
        // profile), else fall back to the shell so the app still mounts.
        const cached = (await cache.match(req)) || (await cache.match(SHELL))
        const network = fetch(req)
          .then((res) => {
            if (res && res.status === 200) cache.put(req, res.clone())
            return res
          })
          .catch(() => cached)
        return cached || network
      })(),
    )
    return
  }

  // ponytail: everything else (assets, GET server-fn RPC) — runtime SWR.
  event.respondWith(
    (async () => {
      const cache = await caches.open(CACHE)
      const cached = await cache.match(req)
      const network = fetch(req)
        .then((res) => {
          if (res && res.status === 200) cache.put(req, res.clone())
          return res
        })
        .catch(() => cached)
      return cached || network
    })(),
  )
})
